        at: new Date().toISOString(),
        stage: "smart_extraction",
        reason: modelResult.degradeReason,
        details: modelResult.degradeReason === "smart_extraction_candidates_empty" && smartExtractionFallbackDetails ? `${modelResult.details} source_messages=${smartExtractionFallbackDetails.sourceMessageCount}; workflow_segments=${smartExtractionFallbackDetails.workflowSegments}; distinct_workflow_messages=${smartExtractionFallbackDetails.distinctWorkflowMessages}; unique_workflow_segments=${smartExtractionFallbackDetails.uniqueWorkflowSegments}` : modelResult.details,
